package com.alibaba.fastjson2.filter;

import com.alibaba.fastjson2.JSONWriter;

import java.util.ArrayList;
import java.util.List;

final class CompositePropertyPreFilter
        implements PropertyPreFilter {
    private final List<PropertyPreFilter> filters = new ArrayList<>();

    public CompositePropertyPreFilter(PropertyPreFilter... filters) {
        for (PropertyPreFilter filter : filters) {
            if (filter != null) {
                this.filters.add(filter);
            }
        }
    }

    public void add(PropertyPreFilter filter) {
        if (filter != null) {
            this.filters.add(filter);
        }
    }

    @Override
    public boolean process(JSONWriter writer, Object source, String name) {
        for (PropertyPreFilter filter : filters) {
            if (!filter.process(writer, source, name)) {
                return false;
            }
        }
        return true;
    }
}

package com.alibaba.fastjson2.filter;

import com.alibaba.fastjson2.PropertyNamingStrategy;
import com.alibaba.fastjson2.util.BeanUtils;

import java.util.function.Function;

public interface NameFilter
        extends Filter {
    String process(Object object, String name, Object value);

    static NameFilter of(PropertyNamingStrategy namingStrategy) {
        return (object, name, value) -> BeanUtils.fieldName(name, namingStrategy.name());
    }

    static NameFilter compose(NameFilter before, NameFilter after) {
        return (object, name, value) ->
                after.process(
                        object,
                        before.process(object, name, value),
                        value
                );
    }

    static NameFilter of(Function<String, String> function) {
        return (object, name, value) -> function.apply(name);
    }
}

package com.alibaba.fastjson2.function.impl;

import com.alibaba.fastjson2.JSONException;

import java.math.BigDecimal;
import java.math.BigInteger;
import java.util.concurrent.atomic.AtomicInteger;
import java.util.concurrent.atomic.AtomicLong;
import java.util.function.Function;

public class ToBigInteger
        implements Function {
    @Override
    public Object apply(Object o) {
        if (o == null || o instanceof BigInteger) {
            return o;
        }

        if (o instanceof Boolean) {
            return (Boolean) o ? BigInteger.ONE : BigInteger.ZERO;
        }

        if (o instanceof Byte
                || o instanceof Short
                || o instanceof Integer
                || o instanceof Long
                || o instanceof AtomicInteger
                || o instanceof AtomicLong
                || o instanceof Float
                || o instanceof Double
        ) {
            return BigInteger.valueOf(((Number) o).longValue());
        }

        if (o instanceof BigDecimal) {
            return ((BigDecimal) o).toBigInteger();
        }

        throw new JSONException("can not cast to BigInteger " + o.getClass());
    }
}

package com.alibaba.fastjson2;

import com.alibaba.fastjson2.util.IOUtils;

import static com.alibaba.fastjson2.JSONWriter.Feature.WriteBooleanAsNumber;
import static com.alibaba.fastjson2.util.JDKUtils.*;

final class JSONWriterUTF16JDK9UF
        extends JSONWriterUTF16 {
    JSONWriterUTF16JDK9UF(Context ctx) {
        super(ctx);
    }

    @Override
    public void writeString(String str) {
        if (str == null) {
            writeStringNull();
            return;
        }

        final byte[] value = STRING_VALUE.apply(str);
        if (STRING_CODER.applyAsInt(str) == 0) {
            writeStringLatin1(value);
        } else {
            writeStringUTF16(value);
        }
    }

    public void writeBool(boolean value) {
        int minCapacity = off + 5;
        if (minCapacity >= this.chars.length) {
            grow0(minCapacity);
        }

        char[] chars = this.chars;
        int off = this.off;
        if ((context.features & WriteBooleanAsNumber.mask) != 0) {
            chars[off++] = value ? '1' : '0';
        } else {
            off = IOUtils.putBoolean(chars, off, value);
        }
        this.off = off;
    }
}

